class Nesbot < Formula
  desc "Deterministic, policy-driven engineering automation CLI"
  homepage "https://github.com/NesloTechnologies/nesbot"
  url "https://github.com/NesloTechnologies/homebrew-nesbot/releases/download/v1.12.0/nesbot-1.12.0-darwin-arm64.tar.gz"
  sha256 "349a401ff278c325248ec986bcafed4d70d9b097939d5de66e5ba3a903d047fc"
  version "1.12.0"
  license "MIT"

  def install
    libexec.install Dir["*"]

    # Create a wrapper script that invokes the CLI via the system node
    # Requires Node.js >= 18 (nvm, brew node, or system install)
    (bin/"nesbot").write <<~EOS
      #!/usr/bin/env bash
      exec node "#{libexec}/bin/nesbot.js" "$@"
    EOS
  end

  test do
    # Verify the CLI starts and can init a repo
    system bin/"nesbot", "init", "--repo", testpath/"test-repo"
    assert_predicate testpath/"test-repo/.nesbot/config.json", :exist?
  end
end
